23	    fn trace(&self, m: &mut Marker) {
24	        // C: `traversethread` in lgc.c walks the live portion of the stack
25	        // (`stack..top`) and the open-upvalue list. Slots past `top` are
26	        // dead and must not be visited.
27	        let top = self.top.0 as usize;
28	        let end = top.min(self.stack.len());
29	        for slot in &self.stack[..end] {
30	            slot.val.trace(m);
31	        }
32	
33	        for uv in self.openupval.iter() {
34	            uv.trace(m);
35	        }
36	
37	        // PORT NOTE: `global` (Rc<RefCell<GlobalState>>) is reached from the
38	        // heap's root via GlobalState::trace; tracing it from each thread
39	        // would re-enter the root and is explicitly excluded.
