/// Holds the gray queue during a mark phase. Passed to `Trace::trace`.
///
/// During the Phase A/B/C/D-0 window the live universe holds `GcRef<T>`
/// (`Rc<T>`) rather than the real `Gc<T>`, so the gray queue is unused and
/// trace recursion dispatches directly through `Deref`. Cycles in the
/// object graph (e.g. `_G._G == _G`) would otherwise stack-overflow.
/// `seen` records each visited object's identity so each is traced once
/// per cycle. Phase D's real mark-queue subsumes this via the `Color`
/// flag on `GcHeader`; the set then becomes redundant but is kept harmless.
pub struct Marker {
    gray_queue: Vec<NonNull<GcBox<dyn Trace>>>,
    seen: HashSet<usize>,
}

impl Marker {
    fn new() -> Self {
        Self {
            gray_queue: Vec::with_capacity(256),
            seen: HashSet::with_capacity(256),
        }
    }

    /// Mark a `Gc<T>` as gray (reachable, but its outgoing edges not yet
    /// traced). Called by `Trace::trace` implementations.
    pub fn mark<T: Trace + 'static>(&mut self, gc: Gc<T>) {
        let header = gc.header();
        if header.color.get() == Color::White {
            header.color.set(Color::Gray);
            // Coerce to NonNull<GcBox<dyn Trace>> so we can store in a
            // heterogeneous queue. Requires T: Sized for the unsizing.
            let ptr: NonNull<GcBox<dyn Trace>> = gc.ptr;
            self.gray_queue.push(ptr);
        }
    }

    /// Record an object as visited by its identity (typically the address
    /// of the underlying allocation). Returns `true` the first time an id
    /// is seen and `false` for every subsequent call. Trace impls use this
    /// to guard recursive dispatch through `GcRef<T>` so cycles terminate.
    pub fn enter(&mut self, id: usize) -> bool {
        self.seen.insert(id)
    }
}

