/// LuaValue — central enum. Variants Nil/Bool/Int/Float/LightUserData carry
/// no GC; Str/Table/Function/UserData/Thread carry collectable payloads.
impl Trace for LuaValue {
    fn trace(&self, m: &mut Marker) {
        match self {
            LuaValue::Nil
            | LuaValue::Bool(_)
            | LuaValue::Int(_)
            | LuaValue::Float(_)
            | LuaValue::LightUserData(_) => {}
            LuaValue::Str(s) => s.trace_obj(m),
            LuaValue::Table(t) => t.trace_obj(m),
            LuaValue::Function(c) => c.trace_obj(m),
            LuaValue::UserData(u) => u.trace_obj(m),
            LuaValue::Thread(_t) => {
                // PORT NOTE: GcRef<LuaThread> is a placeholder unit type in
                // lua-types; the real LuaState lives in lua-vm and is traced
                // through GlobalState::mainthread / state.openupval, not
                // here.
            }
        }
    }
}

/// LuaUserData — metatable plus a fixed number of slot user values. The
/// recursion into the metatable goes through `GcRef::trace_obj` so the
/// cycle guard catches `udata.mt == udata.mt` and similar.
impl Trace for crate::value::LuaUserData {
    fn trace(&self, m: &mut Marker) {
        if let Some(mt) = self.metatable() {
            mt.trace_obj(m);
        }
        for v in self.uv.iter() {
            v.trace(m);
        }
    }
}

