19	/// Cycle-breaking forwarder for the Phase A-D-0 `GcRef<T>` (an `Rc<T>`
20	/// newtype). Real `Gc<T>` defers tracing through the gray queue, which is
21	/// inherently cycle-safe; until the runtime fully transitions, recursive
22	/// `Trace` impls would otherwise blow the Rust call stack on self-referential
23	/// graphs (the global table is reachable from itself via `_G._G == _G`).
24	/// Every `gc_ref.trace(m)` site dispatches through this impl, so registering
25	/// the pointer identity once per collection suffices to break the loop.
26	impl<T: Trace + ?Sized> Trace for GcRef<T> {
27	    fn trace(&self, m: &mut Marker) {
28	        if m.try_visit(self.identity()) {
29	            (**self).trace(m);
30	        }
31	    }
32	}
