34	/// LuaValue — central enum. Variants Nil/Bool/Int/Float/LightUserData carry
35	/// no GC; Str/Table/Function/UserData/Thread carry collectable payloads.
36	impl Trace for LuaValue {
37	    fn trace(&self, m: &mut Marker) {
38	        match self {
39	            LuaValue::Nil
40	            | LuaValue::Bool(_)
41	            | LuaValue::Int(_)
42	            | LuaValue::Float(_)
43	            | LuaValue::LightUserData(_) => {}
44	            LuaValue::Str(s) => s.trace(m),
45	            LuaValue::Table(t) => t.trace(m),
46	            LuaValue::Function(c) => c.trace(m),
47	            LuaValue::UserData(u) => {
48	                if let Some(mt) = u.metatable() {
49	                    mt.trace(m);
50	                }
51	                for v in u.uv.iter() {
52	                    v.trace(m);
53	                }
54	            }
55	            LuaValue::Thread(_t) => {
56	                // PORT NOTE: GcRef<LuaThread> is a placeholder unit type in
57	                // lua-types; the real LuaState lives in lua-vm and is traced
58	                // through GlobalState::mainthread / state.openupval, not
59	                // here.
60	            }
61	        }
62	    }
63	}
